**Python Data Model** — набор dunder (double underscore) методов, позволяющих объектам работать с операторами и встроенными функциями.

```python
class Vector:
    def __init__(self, x: float, y: float) -> None:
        self.x, self.y = x, y

    # Арифметические операторы
    def __add__(self, other: 'Vector') -> 'Vector':
        return Vector(self.x + other.x, self.y + other.y)

    def __mul__(self, scalar: float) -> 'Vector':
        return Vector(self.x * scalar, self.y * scalar)

    # Сравнение
    def __eq__(self, other: object) -> bool:
        return isinstance(other, Vector) and self.x == other.x and self.y == other.y

    def __lt__(self, other: 'Vector') -> bool:
        return abs(self) < abs(other)

    # Встроенные функции
    def __len__(self) -> int:
        return 2

    def __abs__(self) -> float:
        return (self.x**2 + self.y**2) ** 0.5

    def __repr__(self) -> str:
        return f'Vector({self.x}, {self.y})'

    # Итерация
    def __iter__(self):
        yield self.x
        yield self.y

v = Vector(3, 4)
print(abs(v))   # 5.0 — вызывает __abs__
print(len(v))   # 2   — вызывает __len__
x, y = v        # распаковка через __iter__
```

