import os
import requests
from typing import Any, Optional


class ApiClient:
    def __init__(self, base_url: str, token: str) -> None:
        self._base_url = base_url.rstrip('/')
        self._session = requests.Session()
        self._session.headers.update({
            'Authorization': f'Bearer {token}',
            'Content-Type': 'application/json',
            'Accept': 'application/json',
        })

    @classmethod
    def from_env(cls) -> 'ApiClient':
        base_url = os.environ.get('BASE_URL', 'http://localhost:8000')
        token = os.environ['API_TOKEN']  # обязателен — KeyError если нет
        return cls(base_url, token)

    def get(self, endpoint: str, params: Optional[dict] = None) -> requests.Response:
        return self._session.get(f'{self._base_url}{endpoint}', params=params)

    def post(self, endpoint: str, json: Any = None) -> requests.Response:
        return self._session.post(f'{self._base_url}{endpoint}', json=json)

    def delete(self, endpoint: str) -> requests.Response:
        return self._session.delete(f'{self._base_url}{endpoint}')

    def close(self) -> None:
        self._session.close()

import time
from functools import wraps


def retry(times: int = 3, delay: float = 0.1, exceptions: tuple = (Exception,)):
    """Декоратор для повторного вызова функции при исключении."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None
            for attempt in range(1, times + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    last_exception = e
                    if attempt < times:
                        time.sleep(delay)
            raise last_exception
        return wrapper
    return decorator


# Тест самого декоратора:
import pytest
from unittest.mock import MagicMock

def test_retry_succeeds_on_third_attempt():
    call_count = 0

    @retry(times=3, delay=0)
    def flaky():
        nonlocal call_count
        call_count += 1
        if call_count < 3:
            raise ConnectionError('Flaky!')
        return 'success'

    result = flaky()
    assert result == 'success'
    assert call_count == 3

def test_retry_raises_after_all_attempts():
    @retry(times=3, delay=0)
    def always_fails():
        raise ConnectionError('Always fails')

    with pytest.raises(ConnectionError):
        always_fails()

